import{_ as e,o as r,c as i,ah as l}from"./chunks/framework.BNo2o5Ln.js";const m=JSON.parse('{"title":"限流","description":"","frontmatter":{"title":"限流","order":5},"headers":[],"relativePath":"server/distribute/micro/rate-limit/index.md","filePath":"server/distribute/micro/rate-limit/index.md"}'),h={name:"server/distribute/micro/rate-limit/index.md"};function n(t,a,p,d,s,o){return r(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="限流" tabindex="-1">限流 <a class="header-anchor" href="#限流" aria-label="Permalink to “限流”">​</a></h1><p>限流是保护服务不被过载请求打垮的重要手段，通过限制请求速率，确保服务在容量范围内稳定运行。限流可以防止恶意攻击、流量突增、资源耗尽。</p><h2 id="为什么需要限流" tabindex="-1">为什么需要限流 <a class="header-anchor" href="#为什么需要限流" aria-label="Permalink to “为什么需要限流”">​</a></h2><p>保护服务：服务容量有限，超过容量的请求会导致服务响应变慢或崩溃。</p><p>保护依赖：服务依赖的第三方服务有容量限制（如 API 配额），超过限制会被封禁。</p><p>防止雪崩：服务故障时，限流可以减少故障服务的请求，避免雪崩。</p><p>公平使用：防止个别用户占用过多资源，保证其他用户的正常使用。</p><h2 id="限流算法" tabindex="-1">限流算法 <a class="header-anchor" href="#限流算法" aria-label="Permalink to “限流算法”">​</a></h2><h3 id="固定窗口" tabindex="-1">固定窗口 <a class="header-anchor" href="#固定窗口" aria-label="Permalink to “固定窗口”">​</a></h3><p>固定窗口将时间分成固定大小的窗口，如 1 分钟，每个窗口内限制请求数。请求到达时，检查当前窗口的请求数，如果未超过限制则放行，否则拒绝。</p><p>固定窗口的问题：窗口边界问题（窗口边界处可能有双倍请求）、不平滑（窗口前期大量请求，后期无请求）。</p><h3 id="滑动窗口" tabindex="-1">滑动窗口 <a class="header-anchor" href="#滑动窗口" aria-label="Permalink to “滑动窗口”">​</a></h3><p>滑动窗口将时间分成更小的单元，如 1 秒，记录每个单元的请求数。请求到达时，统计最近时间窗口（如 1 分钟）的请求数，如果未超过限制则放行，否则拒绝。</p><p>滑动窗口的优势：平滑、无边界问题。</p><p>滑动窗口的问题：内存占用大（需要记录每个单元的请求数）、实现复杂。</p><h3 id="漏桶" tabindex="-1">漏桶 <a class="header-anchor" href="#漏桶" aria-label="Permalink to “漏桶”">​</a></h3><p>漏桶以恒定速率处理请求，请求先进入桶中，桶满后拒绝请求。漏桶的速率固定，输出平滑。</p><p>漏桶的优势：平滑输出、可以应对突发流量（桶可以缓存一定请求）。</p><p>漏桶的问题：无法应对持续突发流量（桶满后拒绝请求）、桶的大小需要合理设置。</p><h3 id="令牌桶" tabindex="-1">令牌桶 <a class="header-anchor" href="#令牌桶" aria-label="Permalink to “令牌桶”">​</a></h3><p>令牌桶以恒定速率放入令牌，请求到达时消耗令牌，有令牌则放行，否则拒绝。令牌桶可以应对突发流量（桶中可以积累令牌）。</p><p>令牌桶的优势：可以应对突发流量、限流速率可变（动态调整令牌放入速率）。</p><p>令牌桶的问题：实现复杂、需要合理设置桶的大小和令牌放入速率。</p><h3 id="分布式限流" tabindex="-1">分布式限流 <a class="header-anchor" href="#分布式限流" aria-label="Permalink to “分布式限流”">​</a></h3><p>单机限流只能限制单个实例的请求，分布式限流需要限制所有实例的总请求。分布式限流可以通过 Redis 实现，使用 INCR 或 Lua 脚本实现原子计数。</p><p>分布式限流的问题：Redis 成为瓶颈、Redis 故障影响限流、网络延迟影响限流精度。</p><h2 id="限流维度" tabindex="-1">限流维度 <a class="header-anchor" href="#限流维度" aria-label="Permalink to “限流维度”">​</a></h2><h3 id="qps-限流" tabindex="-1">QPS 限流 <a class="header-anchor" href="#qps-限流" aria-label="Permalink to “QPS 限流”">​</a></h3><p>每秒请求数限流，限制每秒的请求数。适用于短时间请求。</p><h3 id="并发限流" tabindex="-1">并发限流 <a class="header-anchor" href="#并发限流" aria-label="Permalink to “并发限流”">​</a></h3><p>并发请求数限流，限制同时处理的请求数。适用于长连接请求。</p><h3 id="用户限流" tabindex="-1">用户限流 <a class="header-anchor" href="#用户限流" aria-label="Permalink to “用户限流”">​</a></h3><p>根据用户 ID 限流，限制每个用户的请求速率。防止个别用户占用过多资源。</p><h3 id="ip-限流" tabindex="-1">IP 限流 <a class="header-anchor" href="#ip-限流" aria-label="Permalink to “IP 限流”">​</a></h3><p>根据 IP 限流，限制每个 IP 的请求速率。防止恶意攻击。</p><h3 id="接口限流" tabindex="-1">接口限流 <a class="header-anchor" href="#接口限流" aria-label="Permalink to “接口限流”">​</a></h3><p>根据接口限流，不同接口设置不同的限流策略。核心接口限流宽松，非核心接口限流严格。</p><h2 id="限流策略" tabindex="-1">限流策略 <a class="header-anchor" href="#限流策略" aria-label="Permalink to “限流策略”">​</a></h2><h3 id="直接拒绝" tabindex="-1">直接拒绝 <a class="header-anchor" href="#直接拒绝" aria-label="Permalink to “直接拒绝”">​</a></h3><p>请求超过限流阈值时直接拒绝，返回错误码或错误信息。简单但影响用户体验。</p><h3 id="排队等待" tabindex="-1">排队等待 <a class="header-anchor" href="#排队等待" aria-label="Permalink to “排队等待”">​</a></h3><p>请求超过限流阈值时排队等待，有请求完成则处理排队请求。可以保证所有请求最终被处理，但会增加延迟。</p><h3 id="warm-up" tabindex="-1">Warm Up <a class="header-anchor" href="#warm-up" aria-label="Permalink to “Warm Up”">​</a></h3><p>限流阈值从较小值逐渐增加到目标值，避免系统启动时大量请求导致故障。适用于缓存预热、系统启动。</p><h3 id="匀速排队" tabindex="-1">匀速排队 <a class="header-anchor" href="#匀速排队" aria-label="Permalink to “匀速排队”">​</a></h3><p>请求以匀速通过，平滑处理请求。漏桶和令牌桶都可以实现匀速排队。</p><h2 id="主流限流实现" tabindex="-1">主流限流实现 <a class="header-anchor" href="#主流限流实现" aria-label="Permalink to “主流限流实现”">​</a></h2><h3 id="sentinel" tabindex="-1">Sentinel <a class="header-anchor" href="#sentinel" aria-label="Permalink to “Sentinel”">​</a></h3><p>Sentinel 是阿里开源的流量防卫组件，提供限流、熔断降级、系统保护。</p><p>Sentinel 的限流：QPS 限流（直接拒绝、Warm Up、匀速排队）、并发线程数限流、热点参数限流。</p><p>Sentinel 的优势：性能高、实时监控、规则动态配置、生态完善。</p><h3 id="guava-ratelimiter" tabindex="-1">Guava RateLimiter <a class="header-anchor" href="#guava-ratelimiter" aria-label="Permalink to “Guava RateLimiter”">​</a></h3><p>Guava RateLimiter 是 Google Guava 的限流库，基于令牌桶算法。</p><p>Guava RateLimiter 的特性：平滑限流、支持预热、简单易用。</p><p>Guava RateLimiter 的问题：单机限流、不支持分布式。</p><h3 id="redis-lua" tabindex="-1">Redis + Lua <a class="header-anchor" href="#redis-lua" aria-label="Permalink to “Redis + Lua”">​</a></h3><p>使用 Redis 存储计数，Lua 脚本保证原子性，可以实现分布式限流。</p><p>Redis + Lua 的优势：分布式、性能高、灵活。</p><p>Redis + Lua 的问题：Redis 成为瓶颈、需要处理 Redis 故障。</p><h3 id="nginx-限流" tabindex="-1">Nginx 限流 <a class="header-anchor" href="#nginx-限流" aria-label="Permalink to “Nginx 限流”">​</a></h3><p>Nginx 提供 limit_req_module（漏桶）和 limit_conn_module（并发限流）。</p><p>Nginx 限流的优势：网关层限流、性能高、配置简单。</p><p>Nginx 限流的问题：只能限制经过 Nginx 的请求、不支持复杂限流策略。</p><h2 id="限流的最佳实践" tabindex="-1">限流的最佳实践 <a class="header-anchor" href="#限流的最佳实践" aria-label="Permalink to “限流的最佳实践”">​</a></h2><p>分层限流：网关层限流（粗粒度）、应用层限流（细粒度），形成多级防护。</p><p>限流阈值设置：根据压测结果设置限流阈值，留有余量。根据业务重要性设置不同的限流策略。</p><p>限流监控：监控限流触发情况，分析限流原因，调整限流策略。</p><p>限流告警：限流触发时及时告警，便于快速响应。</p><p>限流降级：限流触发时可以降级处理，返回默认值或错误响应。</p><p>限流预热：系统启动时使用 Warm Up 策略，避免启动时大量请求导致故障。</p><p>限流是保护服务的重要手段，理解限流算法和权衡，有助于设计合适的限流方案。</p>',71)])])}const b=e(h,[["render",n]]);export{m as __pageData,b as default};
